const query = ($json.query || '').trim();
const telefone = ($json.telefone || '').replace('@s.whatsapp.net', '');

// Stop words PT + ES + comandos comuns
const ignore = [
  'quero','apagar','excluir','deletar','buscar','encontrar',
  'pode','mostrar','listar','ver','editar','mudar','alterar',
  'registro','registros','transação','transacao','gasto','gastos',
  'quiere','quiero','borrar','eliminar','puede','puedes',
  'la','el','un','una','los','las','de','del','para','por',
  'con','que','ese','esa','este','esta','como','mis',
  'o','a','os','as','do','da','dos','das','no','na',
  'nos','nas','em','com','meu','meus','minha','minhas'
];

// Extrai palavras significativas
let words = query.toLowerCase()
  .replace(/[?!.,;:'"()\-]/g, '')
  .split(/\s+/)
  .filter(word => word.length > 1 && !ignore.includes(word));

let cleanQuery = words.join(' ');

// Fallback: última palavra significativa
if (!cleanQuery) {
  const originalWords = query.toLowerCase()
    .replace(/[?!.,;:'"()\-]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 2);
  cleanQuery = originalWords[originalWords.length - 1] || query.trim();
}

return [{
  json: {
    searchTerm: cleanQuery,
    originalQuery: query,
    telefone: telefone
  }
}];

const parsed = $node['Parsear Query'].json;
const resposta = $input.first().json;
const searchTerm = (parsed.searchTerm || '').toLowerCase();

const transacciones = resposta.transacciones || [];

if (transacciones.length === 0) {
  return [{ json: {
    success: true,
    message: `🔍 No encontré transacciones para tu familia.`
  }}];
}

// Busca case-insensitive + sem acentos
function normalize(str) {
  return (str || '').toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

const searchNorm = normalize(searchTerm);

// Filtra por descrição OU categoria
const matches = transacciones.filter(t => {
  const desc = normalize(t.descripcion);
  const cat = normalize(t.categoria);
  return desc.includes(searchNorm) || cat.includes(searchNorm);
});

if (matches.length === 0) {
  return [{ json: {
    success: true,
    message: `🔍 No encontré transacciones que coincidan con "${parsed.searchTerm}".\n\nTus últimas transacciones son:\n${resposta.message || '(ninguna)'}`
  }}];
}

let msg = `🔍 *Encontré ${matches.length} transaccion(es):*\n\n`;
matches.slice(0, 5).forEach(t => {
  const emoji = t.tipo === 'pago' ? '📉' : '📈';
  const monto = Number(t.monto).toLocaleString('es-CO');
  msg += `${emoji} *${t.descripcion}*\n💰 $${monto} | 📂 ${t.categoria}\n🆔 \`${t.id}\`\n\n`;
});

return [{ json: {
  success: true,
  message: msg.trim(),
  data: matches.slice(0, 5)
}}];
